import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useLanguage } from '../context/LanguageContext';
import { Mic, Square, Play, ArrowLeft, Send, ShieldCheck, User, MapPin } from 'lucide-react';

export default function ChatScreen({ firData, setFirData }) {
  const { t, language } = useLanguage();
  const navigate = useNavigate();
  const messagesEndRef = useRef(null);
  const recognitionRef = useRef(null);

  const questions = [
    { id: 'name', text: t('q_name') },
    { id: 'father_name', text: t('q_father_name') },
    { id: 'mobile', text: t('q_mobile') },
    { id: 'address', text: t('q_address') },
    { id: 'incident_type', text: t('q_type') },
    { id: 'date_time', text: t('q_date') },
    { id: 'location', text: t('q_location') },
    { id: 'description', text: t('q_desc') },
    { id: 'suspect', text: t('q_suspect') },
    { id: 'witness', text: t('q_witness') },
    { id: 'done', text: t('q_out') }
  ];

  const [currentStep, setCurrentStep] = useState(0);
  const [messages, setMessages] = useState([
    { sender: 'bot', text: questions[0].text }
  ]);
  const [inputText, setInputText] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isTyping, setIsTyping] = useState(false);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const speakText = (text) => {
    const cleanText = text.replace(/^\d+\.\s*/, '');
    const utterance = new SpeechSynthesisUtterance(cleanText);

    // Map language to the required locale, defaulting to US English
    const langMap = { en: 'en-US', hi: 'hi-IN', te: 'te-IN' };
    utterance.lang = langMap[language] || 'en-US'; 

    window.speechSynthesis.speak(utterance);
  };

  useEffect(() => {
    if ('speechSynthesis' in window) {
      window.speechSynthesis.getVoices();
      window.speechSynthesis.onvoiceschanged = () => window.speechSynthesis.getVoices();
    }
  }, []);

  const replayCurrentQuestion = () => {
    const currentQ = messages.filter(m => m.sender === 'bot').pop();
    if (currentQ) {
      speakText(currentQ.text);
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  useEffect(() => {
    // If mic is turned off and we have text, auto-send it
    if (!isRecording && inputText.trim() !== '') {
      handleSend();
    }
  }, [isRecording]);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = true;

      const langMap = { en: 'en-US', hi: 'hi-IN', te: 'te-IN' };
      recognitionRef.current.lang = langMap[language] || 'en-US';

      recognitionRef.current.onresult = (event) => {
        let interimTranscript = '';
        let finalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          } else {
            interimTranscript += event.results[i][0].transcript;
          }
        }

        // Update input text with what's spoken so far
        setInputText((prev) => (finalTranscript ? finalTranscript : interimTranscript));
      };

      recognitionRef.current.onerror = (event) => {
        console.error("Speech recognition error", event.error);
        setIsRecording(false);
      };

      recognitionRef.current.onend = () => {
        setIsRecording(false);
      };
    }
  }, [language]);

  const detectIncidentType = (text) => {
    const lowerText = text.toLowerCase();
    if (lowerText.includes('stole') || lowerText.includes('theft') || lowerText.includes('robbed') || lowerText.includes('α░Üα▒ïα░░α▒Ç') || lowerText.includes('αñÜαÑïαñ░αÑÇ')) {
      return 'Theft';
    } else if (lowerText.includes('lost') || lowerText.includes('missing') || lowerText.includes('αñûαÑï αñùαñ»αñ╛') || lowerText.includes('α░¬α▒ïα░ùα▒èα░ƒα▒ìα░ƒα▒üα░òα▒üα░¿α▒ìα░¿α░╛α░¿α▒ü')) {
      return 'Lost Item';
    } else if (lowerText.includes('fraud') || lowerText.includes('scam') || lowerText.includes('bank') || lowerText.includes('αñºα▒ïα░û') || lowerText.includes('α░«α▒ïα░╕α░é')) {
      return 'Cyber Fraud';
    }
    return 'Other';
  };

  const handleSend = async () => {
    if (!inputText.trim()) return;
    processMessage(inputText);
  };

  const processMessage = async (text) => {
    const userMessage = text;
    setInputText('');
    setMessages(prev => [...prev, { sender: 'user', text: userMessage.split('|')[0] }]);

    // Save data based on current step
    const currentQ = questions[currentStep];
    const newFirData = { ...firData };

    if (currentQ.id === 'incident_type') {
      const detected = detectIncidentType(userMessage);
      newFirData[currentQ.id] = detected;
      // We can also store the raw user response in description as a starting point
      newFirData.description = userMessage + ". ";
    } else if (currentQ.id === 'location' && userMessage.toLowerCase().includes('gps')) {
      // Mock GPS
      newFirData[currentQ.id] = "Current GPS Location (Lat: 17.3850, Long: 78.4867)";
    } else if (currentQ.id !== 'done') {
      if (currentQ.id === 'description') {
        newFirData.description += userMessage;
      } else {
        newFirData[currentQ.id] = userMessage;
      }
    }

    setFirData(newFirData);

    // Move to next question
    if (currentStep < questions.length - 1) {
      setIsTyping(true);
      setTimeout(() => {
        setIsTyping(false);
        const nextPrompt = questions[currentStep + 1].text;
        setMessages(prev => [...prev, { sender: 'bot', text: nextPrompt }]);
        speakText(nextPrompt);
        setCurrentStep(prev => prev + 1);

        if (currentStep + 1 === questions.length - 1) {
          // It's the "done" message, navigate automatically after a short delay
          setTimeout(() => {
             navigate('/review');
          }, 2000);
        }
      }, 1000);
    }
  };

  const toggleRecording = () => {
    if (!isRecording) {
      if (recognitionRef.current) {
        setInputText(''); // Clear existing input before recording
        setIsRecording(true);
        recognitionRef.current.start();
      } else {
        alert("Microphone & Speech recognition is not supported in this browser.");
      }
    } else {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
      setIsRecording(false);
    }
  };

  const handleGPS = () => {
    if ("geolocation" in navigator) {
      setIsTyping(true);
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setIsTyping(false);
          const lat = position.coords.latitude;
          const lon = position.coords.longitude;
          const mapUrl = `https://www.openstreetmap.org/export/embed.html?bbox=${lon-0.02},${lat-0.02},${lon+0.02},${lat+0.02}&layer=mapnik&marker=${lat},${lon}`;
          const locStr = `Detected GPS: ${lat.toFixed(4)}, ${lon.toFixed(4)}|${mapUrl}`;
          processMessage(locStr);
        },
        (error) => {
          setIsTyping(false);
          alert("Could not get GPS location. Please type manually.");
        }
      );
    } else {
      alert("Geolocation is not supported by your browser");
    }
  };

  const currentMainQuestion = messages.filter(m => m.sender === 'bot').pop()?.text;

  return (
    <div className="chat-screen">
      <div className="app-header">
        <button className="back-btn" onClick={() => navigate(-1)}>
          <ArrowLeft size={20} />
        </button>
        <span className="app-title">CIVIC GUARDIAN</span>
        <div className="profile-icon">
          <User size={18} />
        </div>
      </div>

      <div className="chat-history">
        {/* We format it nicely according to the UI: large text for bot if it's the latest */}
        {messages.map((msg, index) => {
          const isLatestBot = msg.sender === 'bot' && index === messages.lastIndexOf(messages.filter(m => m.sender === 'bot').pop());
          return (
            <div key={index} className={msg.sender === 'bot' ? 'message-bot' : 'message-user'}>
              {msg.sender === 'bot' ? (
                 <div className="bot-text" style={{ fontSize: isLatestBot ? '24px' : '16px', color: isLatestBot ? 'var(--primary-color)' : 'var(--text-secondary)'}}>
                   {msg.text}
                 </div>
              ) : (
                msg.text
              )}
            </div>
          );
        })}
        {isTyping && (
          <div className="typing-indicator">
            <div className="typing-dot"></div>
            <div className="typing-dot"></div>
            <div className="typing-dot"></div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="voice-controls">
        <div className="mic-status">
          <ShieldCheck size={16} /> 
          {isRecording ? "Listening..." : "Official Statement Recording"}
        </div>

        <div className="mic-button-wrapper">
          {isRecording && <div className="mic-ripple"></div>}
          <button 
            className={`mic-button ${isRecording ? 'recording' : ''}`}
            onClick={toggleRecording}
          >
            {isRecording ? <Square fill="white" size={24} /> : <Mic size={28} />}
          </button>
        </div>

        <div className="control-actions">
          <button className="icon-btn" onClick={replayCurrentQuestion}>
            <Play size={20} />
            REPLAY
          </button>
          <button className="icon-btn stop">
            <Square size={20} />
            STOP
          </button>
          <button className="icon-btn">
            <User size={20} /> {/* Mock TYPE INSTEAD icon using User */}
            TYPE INSTEAD
          </button>
        </div>

        <div className="input-container">
          <input 
            type="text" 
            className="text-input" 
            placeholder="Type your response..."
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            disabled={isRecording || currentStep === questions.length - 1}
          />
          {questions[currentStep]?.id === 'location' && (
            <button 
              className="send-btn" 
              style={{ backgroundColor: '#0f766e', marginRight: 4 }}
              onClick={handleGPS} 
              title="Use GPS"
            >
              <MapPin size={18} />
            </button>
          )}
          <button className="send-btn" onClick={handleSend} disabled={isRecording || currentStep === questions.length - 1}>
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import BottomNav from '../components/BottomNav';
import { Settings, User, CheckCircle2, MapPin, Globe, Bell, Moon, AlertTriangle, ShieldCheck, FileKey, LogOut, ChevronRight, Check, Camera } from 'lucide-react';
import { auth, db } from '../firebase';
import { doc, getDoc, updateDoc, setDoc } from 'firebase/firestore';
import { updateProfile } from 'firebase/auth';
import { useLanguage } from '../context/LanguageContext';

export default function ProfileScreen({ onLogout }) {
  const [darkMode, setDarkMode] = useState(document.documentElement.getAttribute('data-theme') === 'dark');
  const { language, setLanguage } = useLanguage();

  // Profile Data State
  const [isEditing, setIsEditing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const [profileData, setProfileData] = useState({
    name: 'Loading...',
    mobile: 'Loading...',
    gender: 'Not Specified',
    photoUrl: null
  });

  const [editForm, setEditForm] = useState({
    name: '',
    mobile: '',
    gender: 'Not Specified',
    photoUrl: null
  });

  useEffect(() => {
    // Fetch live user profile data on load
    const fetchProfileData = async () => {
      if (!auth.currentUser) return;
      try {
        const userDocRef = doc(db, 'Users', auth.currentUser.uid);
        const userDoc = await getDoc(userDocRef);

        let data = {
          name: auth.currentUser.displayName || 'User',
          mobile: '',
          gender: 'Not Specified',
          photoUrl: null
        };

        if (userDoc.exists()) {
          data = { ...data, ...userDoc.data() };
        }

        setProfileData({
          name: data.name || '',
          mobile: data.mobile || '',
          gender: data.gender || 'Not Specified',
          photoUrl: data.photoUrl || null
        });

        setEditForm({
          name: data.name || '',
          mobile: data.mobile || '',
          gender: data.gender || 'Not Specified',
          photoUrl: data.photoUrl || null
        });

      } catch (err) {
        console.error("Failed to load profile", err);
      } finally {
        setLoading(false);
      }
    };

    fetchProfileData();
  }, []);

  const handlePhotoUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditForm({ ...editForm, photoUrl: reader.result });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDarkModeToggle = () => {
    const isDark = !darkMode;
    setDarkMode(isDark);
    if (isDark) {
      document.documentElement.setAttribute('data-theme', 'dark');
    } else {
      document.documentElement.removeAttribute('data-theme');
    }
  };

  const handleSave = async () => {
    if (!auth.currentUser) return;
    setSaving(true);
    try {
      // 1. Update Firebase Auth Native Profile
      await updateProfile(auth.currentUser, { displayName: editForm.name });

      // 2. Update Firestore Database Document
      const userDocRef = doc(db, 'Users', auth.currentUser.uid);

      // Use setDoc with merge:true in case the doc doesn't fully exist yet for some old users
      await setDoc(userDocRef, {
        name: editForm.name,
        mobile: editForm.mobile,
        gender: editForm.gender,
        photoUrl: editForm.photoUrl
      }, { merge: true });

      // Update local state and close editor
      setProfileData({
        name: editForm.name,
        mobile: editForm.mobile,
        gender: editForm.gender,
        photoUrl: editForm.photoUrl
      });
      setIsEditing(false);
    } catch (err) {
      console.error("Failed to save profile", err);
      alert("Error saving profile: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <div className="profile-screen">
        {/* App Header */}
        <div className="analytics-header">
          <div className="analytics-logo">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M4 22h14a2 2 0 0 0 2-2V7l-5-5H6a2 2 0 0 0-2 2v4"></path>
              <path d="M14 2v4a2 2 0 0 0 2 2h4"></path>
              <path d="m3 15 2 2 4-4"></path>
            </svg>
            Civic Guardian
          </div>
          <div style={{ color: 'var(--text-secondary)' }}>
            <Settings size={22} />
          </div>
        </div>

        <div className="profile-content">

          {/* Profile Info Card */}
          <div className="profile-card" style={{ position: 'relative' }}>

            {/* Edit / Save Action Buttons */}
            <div style={{ position: 'absolute', top: 0, right: 0 }}>
              {!isEditing ? (
                <button
                  onClick={() => setIsEditing(true)}
                  style={{ padding: '6px 14px', borderRadius: 20, backgroundColor: '#f1f5f9', color: '#0f172a', fontWeight: 700, fontSize: 11, letterSpacing: 0.5, border: 'none', cursor: 'pointer' }}
                >
                  EDIT PROFILE
                </button>
              ) : (
                <div style={{ display: 'flex', gap: 6 }}>
                  <button
                    onClick={() => { setIsEditing(false); setEditForm(profileData); }}
                    style={{ padding: '6px 14px', borderRadius: 20, backgroundColor: '#fee2e2', color: '#dc2626', fontWeight: 700, fontSize: 11, border: 'none', cursor: 'pointer' }}
                  >
                    CANCEL
                  </button>
                  <button
                    onClick={handleSave}
                    disabled={saving}
                    style={{ padding: '6px 14px', borderRadius: 20, backgroundColor: '#1e3a8a', color: 'white', fontWeight: 700, fontSize: 11, border: 'none', cursor: 'pointer' }}
                  >
                    {saving ? 'SAVING...' : 'SAVE'}
                  </button>
                </div>
              )}
            </div>

            <div className="avatar-wrapper" style={{ position: 'relative' }}>
              <div className="avatar-img" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', backgroundColor: '#1e293b', overflow: 'hidden', position: 'relative' }}>
                {(isEditing ? editForm.photoUrl : profileData.photoUrl) ? (
                  <img src={isEditing ? editForm.photoUrl : profileData.photoUrl} alt="Profile" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                ) : (
                  <div style={{ width: 44, height: 44, backgroundColor: '#fcd34d', borderRadius: '50%', marginBottom: -20 }}></div>
                )}

                {isEditing && (
                  <>
                    <label htmlFor="photo-upload" style={{ position: 'absolute', inset: 0, backgroundColor: 'rgba(0,0,0,0.4)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', zIndex: 10 }}>
                      <Camera size={24} color="white" />
                      <span style={{ fontSize: 9, color: 'white', fontWeight: 600, marginTop: 4 }}>CHANGE</span>
                    </label>
                    <input
                      id="photo-upload"
                      type="file"
                      accept="image/*"
                      onChange={handlePhotoUpload}
                      style={{ display: 'none' }}
                    />
                  </>
                )}
              </div>
              {!isEditing && (
                <div className="verified-badge-icon">
                  <div className="inner">
                    <Check size={12} strokeWidth={3} />
                  </div>
                </div>
              )}
            </div>

            {isEditing ? (
              <div style={{ textAlign: 'left', marginTop: 24, display: 'flex', flexDirection: 'column', gap: 16 }}>
                <div>
                  <label style={{ fontSize: 10, fontWeight: 700, color: '#64748b', letterSpacing: 0.5, marginBottom: 6, display: 'block' }}>FULL NAME</label>
                  <input
                    type="text"
                    value={editForm.name}
                    onChange={e => setEditForm({ ...editForm, name: e.target.value })}
                    style={{ width: '100%', padding: '12px 14px', borderRadius: 10, border: '1px solid #cbd5e1', backgroundColor: '#f8fafc', fontSize: 14, color: '#0f172a' }}
                  />
                </div>
                <div>
                  <label style={{ fontSize: 10, fontWeight: 700, color: '#64748b', letterSpacing: 0.5, marginBottom: 6, display: 'block' }}>MOBILE NUMBER</label>
                  <input
                    type="text"
                    value={editForm.mobile}
                    onChange={e => setEditForm({ ...editForm, mobile: e.target.value })}
                    placeholder="+91 00000 00000"
                    style={{ width: '100%', padding: '12px 14px', borderRadius: 10, border: '1px solid #cbd5e1', backgroundColor: '#f8fafc', fontSize: 14, color: '#0f172a' }}
                  />
                </div>
                <div>
                  <label style={{ fontSize: 10, fontWeight: 700, color: '#64748b', letterSpacing: 0.5, marginBottom: 6, display: 'block' }}>GENDER</label>
                  <select
                    value={editForm.gender}
                    onChange={e => setEditForm({ ...editForm, gender: e.target.value })}
                    style={{ width: '100%', padding: '12px 14px', borderRadius: 10, border: '1px solid #cbd5e1', backgroundColor: '#f8fafc', fontSize: 14, color: '#0f172a' }}
                  >
                    <option value="Not Specified">Prefer Not to Say</option>
                    <option value="Male">Male</option>
                    <option value="Female">Female</option>
                    <option value="Other">Other</option>
                  </select>
                </div>
              </div>
            ) : (
              <>
                <h2 className="profile-name">{loading ? 'Loading...' : profileData.name}</h2>
                <div className="profile-phone" style={{ marginBottom: 4 }}>
                  {profileData.mobile || 'No Mobile Linked'}
                </div>
                <div className="profile-phone" style={{ fontSize: 12, marginBottom: 16 }}>
                  {profileData.gender !== 'Not Specified' ? profileData.gender : 'Gender Not Specified'}
                </div>

                <div className="badges-row">
                  <div className="badge-pill-blue">CITIZEN ADVOCATE</div>
                  <div className="badge-pill-green">VERIFIED IDENTITY</div>
                </div>
              </>
            )}
          </div>

          {/* Existing Stats UI */}
          <div className="stats-container">
            <div className="stat-box">
              <div className="stat-label">TOTAL REPORTS</div>
              <div className="stat-val">12</div>
            </div>
            <div className="stat-box">
              <div className="stat-label">ACTIVE CASES</div>
              <div className="stat-val">2</div>
            </div>
            <div className="stat-box">
              <div className="stat-label">TRUST SCORE</div>
              <div className="stat-val stat-val-green">98<span className="stat-pct">%</span></div>
            </div>
          </div>

          <h3 className="section-heading">Account Settings</h3>
          <div className="list-card">
            <button className="list-item">
              <div className="list-item-left">
                <div className="list-item-icon"><User size={20} /></div>
                <div className="list-item-text">Personal Information</div>
              </div>
              <div className="list-item-right">
                <ChevronRight size={18} />
              </div>
            </button>

            <button className="list-item">
              <div className="list-item-left">
                <div className="list-item-icon"><ShieldCheck size={20} /></div>
                <div className="list-item-text">
                  Identity Verification
                  <CheckCircle2 size={14} className="verified-icon" />
                </div>
              </div>
              <div className="list-item-right">
                <ChevronRight size={18} />
              </div>
            </button>

            <button className="list-item">
              <div className="list-item-left">
                <div className="list-item-icon"><MapPin size={20} /></div>
                <div className="list-item-text">Saved Addresses</div>
              </div>
              <div className="list-item-right">
                <ChevronRight size={18} />
              </div>
            </button>
          </div>

          <h3 className="section-heading">App Preferences</h3>
          <div className="list-card">
            <div className="list-item" style={{ position: 'relative' }}>
              <div className="list-item-left">
                <div className="list-item-icon"><Globe size={20} /></div>
                <div className="list-item-text">Language</div>
              </div>
              <div className="list-item-right" style={{ display: 'flex', alignItems: 'center' }}>
                <select
                  value={language}
                  onChange={(e) => setLanguage(e.target.value)}
                  style={{ appearance: 'none', background: 'transparent', border: 'none', color: 'var(--text-secondary)', fontSize: '13px', fontWeight: '500', textAlign: 'right', outline: 'none', cursor: 'pointer', paddingRight: '8px' }}
                >
                  <option value="en">English</option>
                  <option value="te">Telugu</option>
                  <option value="hi">Hindi</option>
                </select>
                <ChevronRight size={18} color="var(--text-secondary)" />
              </div>
            </div>

            <button className="list-item">
              <div className="list-item-left">
                <div className="list-item-icon"><Bell size={20} /></div>
                <div className="list-item-text">Notification Settings</div>
